#include<bits/stdc++.h>
using namespace std;
int n,a[11];
int main(){
	cin>>n;
	for(int i=1; i<=n; i++){
	    cin>>a[i];
	    int f=0;
	    for(int j=1;j*j<a[i]&&f==0;j++){
	    	int k=a[i]-j*j;
	    	int v=sqrt(k);
	    	if(v*v==k){
	    		cout<<"Yes"<<endl;
	    		f=1;
	    	}
	    }
	    if(!f)cout<<"No"<<endl;
	}
	return 0;
}
